from mcp.server import Server
from mcp.server.stdio import stdio_server
from mcp import types
import asyncio
import json

app = Server("my-custom-server")

@app.list_tools()
async def list_tools() -> list[types.Tool]:
    return [
        types.Tool(
            name="query_database",
            description="Execute a read-only SQL query against the analytics database.",
            inputSchema={
                "type": "object",
                "properties": {
                    "sql": {
                        "type": "string",
                        "description": "The SELECT query to execute",
                    },
                    "limit": {
                        "type": "integer",
                        "description": "Maximum rows to return (default 100)",
                        "default": 100,
                    },
                },
                "required": ["sql"],
            },
        )
    ]

@app.call_tool()
async def call_tool(name: str, arguments: dict) -> list[types.TextContent]:
    if name == "query_database":
        sql = arguments["sql"]
        limit = arguments.get("limit", 100)
        # Execute query against real database here
        result = {"rows": [], "row_count": 0, "columns": []}  # placeholder
        return [types.TextContent(type="text", text=json.dumps(result, indent=2))]
    raise ValueError(f"Unknown tool: {name}")

async def main():
    async with stdio_server() as streams:
        await app.run(*streams, app.create_initialization_options())

if __name__ == "__main__":
    asyncio.run(main())

from mcp import types

def build_tool_catalogue() -> list[types.Tool]:
    """Return a well-described tool catalogue for Claude to discover."""
    return [
        types.Tool(
            name="search_documents",
            description=(
                "Full-text search across all documents in the knowledge base. "
                "Returns documents ranked by relevance score. Use this when the "
                "user asks about topics, concepts, or specific information that "
                "may be in the documentation. Not suitable for exact ID lookups."
            ),
            inputSchema={
                "type": "object",
                "properties": {
                    "query": {
                        "type": "string",
                        "description": "Natural language search query",
                    },
                    "doc_type": {
                        "type": "string",
                        "enum": ["tutorial", "reference", "guide", "api"],
                        "description": "Filter by document category",
                    },
                    "max_results": {
                        "type": "integer",
                        "minimum": 1,
                        "maximum": 20,
                        "default": 5,
                        "description": "Number of results to return",
                    },
                },
                "required": ["query"],
                "additionalProperties": False,
            },
        ),
        types.Tool(
            name="get_document_by_id",
            description=(
                "Retrieve the full content of a specific document by its unique ID. "
                "Use this after search_documents returns a document ID you need to read in full."
            ),
            inputSchema={
                "type": "object",
                "properties": {
                    "document_id": {
                        "type": "string",
                        "description": "The unique document identifier (e.g. 'doc_abc123')",
                    },
                },
                "required": ["document_id"],
            },
        ),
    ]
